-- Google Shopping & Facebook product category taxonomies (reference data)
-- Sources: Google Product Taxonomy, Meta product categories; labels localized (en/fr); seed uses English only.

CREATE TABLE public.google_product_categories (
    id BIGINT NOT NULL,
    name_en TEXT NOT NULL,
    name_fr TEXT,
    PRIMARY KEY (id)
);

CREATE INDEX idx_google_product_categories_fts
  ON public.google_product_categories
  USING gin (to_tsvector('simple', coalesce(name_en, '') || ' ' || coalesce(name_fr, '')));

COMMENT ON TABLE public.google_product_categories IS 'Google product taxonomy; id matches g:google_product_category in feeds';

CREATE TABLE public.fb_product_categories (
    id INTEGER NOT NULL,
    name_en TEXT NOT NULL,
    name_fr TEXT,
    PRIMARY KEY (id)
);

CREATE INDEX idx_fb_product_categories_fts
  ON public.fb_product_categories
  USING gin (to_tsvector('simple', coalesce(name_en, '') || ' ' || coalesce(name_fr, '')));

COMMENT ON TABLE public.fb_product_categories IS 'Meta (Facebook) product category list; id for commerce integrations';

-- Seed google_product_categories (name_en only; name_fr NULL until translated)














-- Seed fb_product_categories (name_en only; name_fr NULL until translated)










-- item_sub_categories: each internal sub category maps to Google / Facebook taxonomy ids (for feeds, commerce)
ALTER TABLE public.item_sub_categories
  ADD COLUMN google_product_category BIGINT,
  ADD COLUMN fb_product_category INTEGER;

ALTER TABLE public.item_sub_categories
  ADD CONSTRAINT fk_item_sub_categories_google_product_category
    FOREIGN KEY (google_product_category) REFERENCES public.google_product_categories (id) ON UPDATE CASCADE ON DELETE SET NULL,
  ADD CONSTRAINT fk_item_sub_categories_fb_product_category
    FOREIGN KEY (fb_product_category) REFERENCES public.fb_product_categories (id) ON UPDATE CASCADE ON DELETE SET NULL;

CREATE INDEX idx_item_sub_categories_google_product_category
  ON public.item_sub_categories (google_product_category) WHERE google_product_category IS NOT NULL;
CREATE INDEX idx_item_sub_categories_fb_product_category
  ON public.item_sub_categories (fb_product_category) WHERE fb_product_category IS NOT NULL;
